inputDigit.value:
function(digit) {
  const { displayValue, waitingForSecondOperand } = this.state;

  if (waitingForSecondOperand) {
    this.state.displayValue = String(digit);
    this.state.waitingForSecondOperand = false;
  } else {
    this.state.displayValue = displayValue === '0' ? String(digit) : displayValue + digit;
  }
  this.callAction('saveState', { state: this.state });
}

inputDecimal.value:
function() {
  const { displayValue, waitingForSecondOperand } = this.state;

  if (waitingForSecondOperand) {
    this.state.displayValue = '0.';
    this.state.waitingForSecondOperand = false;
  } else if (displayValue.indexOf('.') === -1) {
    this.state.displayValue = displayValue + '.';
  }
  this.callAction('saveState', { state: this.state });
}

handleOperator.value:
function(nextOperator) {
  const { displayValue, firstOperand, operator } = this.state;
  const inputValue = parseFloat(displayValue);

  if (firstOperand === null) {
    this.state.firstOperand = inputValue;
  } else if (operator) {
    const result = this.performCalculation();
    this.state.displayValue = String(result);
    this.state.firstOperand = result;
  }

  this.state.waitingForSecondOperand = true;
  this.state.operator = nextOperator;
  this.callAction('saveState', { state: this.state });
}

performCalculation.value:
function() {
  const { firstOperand, displayValue, operator } = this.state;
  const inputValue = parseFloat(displayValue);

  if (operator === '+') {
    return firstOperand + inputValue;
  } else if (operator === '-') {
    return firstOperand - inputValue;
  } else if (operator === '*') {
    return firstOperand * inputValue;
  } else if (operator === '/') {
    return firstOperand / inputValue;
  }

  return inputValue;
}

clearDisplay.value:
function() {
  this.state.displayValue = '0';
  this.state.firstOperand = null;
  this.state.operator = null;
  this.state.waitingForSecondOperand = false;
  this.callAction('saveState', { state: this.state });
}
